import{_ as s,C as e,o as a,c as o,aw as n,b as l,w as t,a as p,E as c,ag as r}from"./chunks/framework.Dq2onT5h.js";const i=JSON.parse('{"title":"🏠 Local Development Deployment","description":"Deploy an Evolve EVM chain locally for development and testing using ev-toolbox and local-da.","frontmatter":{"description":"Deploy an Evolve EVM chain locally for development and testing using ev-toolbox and local-da.","head":[["meta",{"name":"og:title","content":"🏠 Local Development Deployment | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/deploy/local.md","filePath":"guides/deploy/local.md","lastUpdated":1781702406000}');const d=s({name:"guides/deploy/local.md"},[["render",function(s,i,d,h,u,F){const y=e("Mermaid");return a(),o("div",null,[i[1]||(i[1]=n('<h1 id="🏠-local-development-deployment" tabindex="-1">🏠 Local Development Deployment <a class="header-anchor" href="#🏠-local-development-deployment" aria-label="Permalink to &quot;🏠 Local Development Deployment&quot;">​</a></h1><p>This guide walks you through deploying a complete Evolve EVM chain on your local machine using <a href="https://github.com/evstack/ev-toolbox" target="_blank" rel="noreferrer">ev-toolbox</a>. It uses the <strong>local-da</strong> mock DA layer so there are no external dependencies or token costs.</p><h2 id="🏗️-how-it-works" tabindex="-1">🏗️ How it works <a class="header-anchor" href="#🏗️-how-it-works" aria-label="Permalink to &quot;🏗️ How it works&quot;">​</a></h2><p>The local stack is split into two Docker Compose stacks that share a Docker network (<code>evstack_shared</code>):</p>',4)),(a(),l(r,null,{default:t(()=>[c(y,{id:"mermaid-12",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20%22da-local%20stack%22%0A%20%20%20%20%20%20%20%20LOCAL_DA%5Blocal-da%3Cbr%2F%3E%3A7980%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22single-sequencer%20stack%22%0A%20%20%20%20%20%20%20%20SEQ_RETH%5Bev-reth%3Cbr%2F%3E%3A8545%20JSON-RPC%5D%0A%20%20%20%20%20%20%20%20SEQ_EVM%5Bev-node-evm%3Cbr%2F%3Eaggregator%20mode%5D%0A%20%20%20%20%20%20%20%20SEQ_RETH%20%3C--%3E%20SEQ_EVM%0A%20%20%20%20end%0A%0A%20%20%20%20SEQ_EVM%20--%3E%7CPost%20blobs%7C%20LOCAL_DA%0A%0A%20%20%20%20classDef%20sequencer%20fill%3A%23e1f5fe%0A%20%20%20%20classDef%20da%20fill%3A%23fff3e0%0A%20%20%20%20class%20SEQ_RETH%2CSEQ_EVM%20sequencer%0A%20%20%20%20class%20LOCAL_DA%20da%0A"})]),fallback:t(()=>[...i[0]||(i[0]=[p(" Loading... ",-1)])]),_:1})),i[2]||(i[2]=n('<p>The <code>da-local</code> stack is started first because it creates the shared Docker network that the sequencer stack joins.</p><h2 id="prerequisites" tabindex="-1">💻 Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;💻 Prerequisites {#prerequisites}&quot;">​</a></h2><ul><li><a href="https://docs.docker.com/get-docker/" target="_blank" rel="noreferrer">Docker</a> 20.10 or later</li><li><a href="https://docs.docker.com/compose/install/" target="_blank" rel="noreferrer">Docker Compose</a> v2 or later</li><li><a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a></li></ul><h2 id="clone" tabindex="-1">🛠️ Step 1 — Clone ev-toolbox <a class="header-anchor" href="#clone" aria-label="Permalink to &quot;🛠️ Step 1 — Clone ev-toolbox {#clone}&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">git</span><span style="color:#BFF3C2;"> clone</span><span style="color:#FFECB6;"> --depth</span><span style="color:#FFECB6;"> 1</span><span style="color:#BFF3C2;"> https://github.com/evstack/ev-toolbox.git</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ev-toolbox/ev-stacks/stacks</span></span></code></pre></div><h2 id="start-local-da" tabindex="-1">🌐 Step 2 — Start local-da <a class="header-anchor" href="#start-local-da" aria-label="Permalink to &quot;🌐 Step 2 — Start local-da {#start-local-da}&quot;">​</a></h2><p>The <code>da-local</code> stack must be started first. It creates the <code>evstack_shared</code> Docker network that the sequencer stack joins.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> da-local</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#BFF3C2;"> up</span><span style="color:#FFECB6;"> -d</span></span></code></pre></div><p>Verify it is running:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> logs</span><span style="color:#BFF3C2;"> local-da</span></span></code></pre></div><p>Expected output:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF NewLocalDA: initialized LocalDA component=da</span></span>\n<span class="line"><span>INF Listening on component=da host=0.0.0.0 maxBlobSize=1970176 port=7980</span></span>\n<span class="line"><span>INF server started component=da listening_on=0.0.0.0:7980</span></span></code></pre></div><h2 id="passphrase" tabindex="-1">🔑 Step 3 — Create the passphrase file <a class="header-anchor" href="#passphrase" aria-label="Permalink to &quot;🔑 Step 3 — Create the passphrase file {#passphrase}&quot;">​</a></h2><p>The sequencer signs blocks with a key protected by a passphrase. Create the passphrase file in the single-sequencer directory:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ../single-sequencer</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#FFECB6;"> -n</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">devpassword</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> passphrase</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>For local development, any string works as a passphrase. Keep it simple — you will not need it again unless you restart with a wiped volume.</p></div><h2 id="start-sequencer" tabindex="-1">🚀 Step 4 — Start the sequencer <a class="header-anchor" href="#start-sequencer" aria-label="Permalink to &quot;🚀 Step 4 — Start the sequencer {#start-sequencer}&quot;">​</a></h2><p>Make the entrypoint script executable (required after <code>git clone</code> on some systems), then start the stack using the local-DA variant of the compose file:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">chmod</span><span style="color:#BFF3C2;"> +x</span><span style="color:#BFF3C2;"> entrypoint.sequencer.sh</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.da.local.yml</span><span style="color:#BFF3C2;"> up</span><span style="color:#FFECB6;"> -d</span></span></code></pre></div><p>Monitor startup:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.da.local.yml</span><span style="color:#BFF3C2;"> logs</span><span style="color:#FFECB6;"> -f</span></span></code></pre></div><p>A healthy startup looks like:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>single-sequencer  | 🚀 INIT: Starting EVM Sequencer initialization</span></span>\n<span class="line"><span>single-sequencer  | ✅ SUCCESS: Sequencer initialization completed</span></span>\n<span class="line"><span>single-sequencer  | ✅ SUCCESS: Exported genesis.json to /volumes/sequencer_export/genesis.json</span></span>\n<span class="line"><span>single-sequencer  | ✅ SUCCESS: Successfully retrieved genesis hash: 0x6aec2...</span></span>\n<span class="line"><span>single-sequencer  | 🚀 INIT: Starting EVM sequencer with command: evm start ...</span></span>\n<span class="line"><span>single-sequencer  | INF Starting aggregator node component=main</span></span>\n<span class="line"><span>single-sequencer  | INF produced block component=executor height=1</span></span>\n<span class="line"><span>single-sequencer  | INF produced block component=executor height=2</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">DA submission errors</p><p>You may see errors like <code>DA layer submission failed: method &#39;blob.Submit&#39; not found</code>. This is a known version mismatch between the current local-da Docker images and ev-node-evm. It is <strong>non-fatal</strong> — blocks are produced and the JSON-RPC is fully functional for local development. You can ignore these errors.</p></div><h2 id="verify" tabindex="-1">✅ Step 5 — Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;✅ Step 5 — Verify {#verify}&quot;">​</a></h2><p>The sequencer JSON-RPC port (<code>8545</code>) is not exposed to the host by default. To expose it for local testing, create an override file:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">cat</span><span style="color:#888888;"> &gt;</span><span style="color:#BFF3C2;"> docker-compose.override.yml</span><span style="color:#888888;"> &lt;&lt;</span><span style="color:#BFF3C280;"> &#39;EOF&#39;</span></span>\n<span class="line"><span style="color:#BFF3C2;">services:</span></span>\n<span class="line"><span style="color:#BFF3C2;">  ev-reth-sequencer:</span></span>\n<span class="line"><span style="color:#BFF3C2;">    ports:</span></span>\n<span class="line"><span style="color:#BFF3C2;">      - &quot;8545:8545&quot;</span></span>\n<span class="line"><span style="color:#BFF3C280;">EOF</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.da.local.yml</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.override.yml</span><span style="color:#BFF3C2;"> up</span><span style="color:#FFECB6;"> -d</span></span></code></pre></div><p>Then query the chain:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#FFECB6;"> -s</span><span style="color:#FFECB6;"> -X</span><span style="color:#BFF3C2;"> POST</span><span style="color:#BFF3C2;"> http://localhost:8545</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  -H</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">Content-Type: application/json</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  -d</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">{&quot;jsonrpc&quot;:&quot;2.0&quot;,&quot;method&quot;:&quot;eth_blockNumber&quot;,&quot;params&quot;:[],&quot;id&quot;:1}</span><span style="color:#BFF3C280;">&#39;</span></span></code></pre></div><p>The <code>result</code> field (a hex block number) should increment with each call as new blocks are produced.</p><h2 id="commands" tabindex="-1">🔍 Useful commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;🔍 Useful commands {#commands}&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Check container status</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> ps</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Follow all sequencer logs</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.da.local.yml</span><span style="color:#BFF3C2;"> logs</span><span style="color:#FFECB6;"> -f</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Follow just the ev-node logs (block production)</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> logs</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> single-sequencer</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Follow just the reth logs</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> logs</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> ev-reth-sequencer</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># Stop everything</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#FFECB6;"> -f</span><span style="color:#BFF3C2;"> docker-compose.da.local.yml</span><span style="color:#BFF3C2;"> down</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ../da-local</span><span style="color:#767676;"> &amp;&amp;</span><span style="color:#94EEFF;"> docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#BFF3C2;"> down</span></span></code></pre></div><h2 id="configuration" tabindex="-1">⚙️ Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;⚙️ Configuration {#configuration}&quot;">​</a></h2><p>All configuration is via environment variables in <code>.env</code> and the <code>docker-compose.da.local.yml</code> file.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SEQUENCER_EV_RETH_PROMETHEUS_PORT</code></td><td><code>9000</code></td><td>Host port for ev-reth Prometheus metrics</td></tr><tr><td><code>SEQUENCER_EV_NODE_PROMETHEUS_PORT</code></td><td><code>26660</code></td><td>Host port for ev-node Prometheus metrics</td></tr><tr><td><code>DA_SIGNING_ADDRESSES</code></td><td>(empty)</td><td>DA signing addresses — leave empty for local-da</td></tr><tr><td><code>EVM_BLOCK_TIME</code></td><td><code>500ms</code></td><td>How often the sequencer produces blocks (set in compose)</td></tr></tbody></table><p>To change the block time or other settings, edit <code>docker-compose.da.local.yml</code> directly or add them to your <code>docker-compose.override.yml</code>.</p><h2 id="next-steps" tabindex="-1">🎉 Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;🎉 Next Steps {#next-steps}&quot;">​</a></h2><p>Once your local chain is running:</p><ul><li><a href="./testnet">Testnet Deployment</a> — deploy with real Celestia DA and a multi-node setup</li><li><a href="./../da/local-da">Local DA Guide</a> — more about the <code>local-da</code> mock DA node</li><li><a href="./../metrics">Metrics</a> — add Prometheus + Grafana monitoring</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>This setup is for development only. The <code>local-da</code> mock does not provide real data availability guarantees. Do not use it for any production environment.</p></div>',40))])}]]);export{i as __pageData,d as default};
